// Normalize one WP product. Parses final/was price, discount %, and merchant from prose.
const item = $input.item.json;

const stripHtml = (s) => String(s || '')
  .replace(/<[^>]+>/g, '')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&hellip;/g, '...')
  .replace(/&#8211;/g, '-')
  .replace(/&#8217;/g, "'")
  .replace(/&#8216;/g, "'")
  .replace(/&#8220;/g, '"')
  .replace(/&#8221;/g, '"')
  .replace(/&#8243;/g, '"')
  .replace(/\s+/g, ' ')
  .trim();

const title = stripHtml(item.title && item.title.rendered);
const content = stripHtml(item.content && item.content.rendered);
const excerpt = stripHtml(item.excerpt && item.excerpt.rendered);
const searchSpace = `${content} ${title}`;

const eqMatch = searchSpace.match(/=\s*\$([0-9,]+(?:\.\d{2})?)/);
const forMatch = searchSpace.match(/for\s+\$([0-9,]+(?:\.\d{2})?)/i);
const titleDollar = title.match(/\$([0-9,]+(?:\.\d{2})?)/);
const finalPriceStr = (eqMatch && eqMatch[1]) || (forMatch && forMatch[1]) || (titleDollar && titleDollar[1]) || null;
const finalPrice = finalPriceStr ? parseFloat(finalPriceStr.replace(/,/g, '')) : null;

const firstDollar = content.match(/\$([0-9,]+(?:\.\d{2})?)/);
const wasPriceStr = (firstDollar && finalPriceStr && firstDollar[1] !== finalPriceStr) ? firstDollar[1] : null;
const wasPrice = wasPriceStr ? parseFloat(wasPriceStr.replace(/,/g, '')) : null;

const pctMatch = content.match(/(\d{1,2})\s*%\s*off/i);
let discountPct = pctMatch ? parseInt(pctMatch[1], 10) : null;
if (discountPct == null && wasPrice && finalPrice && wasPrice > finalPrice) {
  discountPct = Math.round(((wasPrice - finalPrice) / wasPrice) * 100);
}

const viaMatch = content.match(/^([A-Za-z0-9 .&'-]{2,40})\s+Via\s+Amazon/);
const merchant = (viaMatch && viaMatch[1].trim()) || (/\bAmazon\b/i.test(content) ? 'Amazon' : null);

const featured = item._embedded && item._embedded['wp:featuredmedia'] && item._embedded['wp:featuredmedia'][0];
const image = featured && featured.source_url ? featured.source_url : null;

const blurb = excerpt.length > 140 ? excerpt.slice(0, 137) + '...' : excerpt;
const category = (item.product_cat && item.product_cat[0]) != null ? item.product_cat[0] : null;

return {
  json: {
    id: item.id,
    title,
    url: item.link,
    image,
    finalPrice,
    wasPrice,
    discountPct,
    priceLabel: finalPrice != null ? `$${finalPrice.toFixed(2)}` : null,
    wasPriceLabel: wasPrice != null ? `$${wasPrice.toFixed(2)}` : null,
    merchant,
    blurb,
    category,
    date: item.date
  }
};

// Paste this into the "Top 8" node — but FIRST change its type from
// "Limit" to "Code". Easiest way: delete the Limit node, drop in a new
// Code node in its place, name it "Rank & Select Top 8", paste this in.
// Mode: Run Once for All Items · Language: JavaScript

const TARGET_COUNT = 8;
const MIN_COUNT = 4;

const products = $input.all().map(i => i.json);

// Dedupe by URL
const seen = new Set();
const deduped = [];
for (const p of products) {
  if (!p.url || seen.has(p.url)) continue;
  seen.add(p.url);
  deduped.push(p);
}

// Score: discount-weighted, with recency tiebreaker bonus
const score = (p) => {
  let s = 0;
  if (p.discountPct != null) s += 50 + p.discountPct * 0.5;
  else if (p.finalPrice != null) s += 30;
  else s += 10;
  const ageHours = (Date.now() - new Date(p.date).getTime()) / 36e5;
  if (ageHours < 24) s += 10;
  return s;
};

const ranked = deduped
  .map((p) => ({ ...p, _score: score(p) }))
  .sort((a, b) => b._score - a._score || new Date(b.date) - new Date(a.date));

// Category diversity: cap per-category at ceil(N/2), but only when 3+ distinct cats present
const distinctCats = new Set(ranked.map((p) => p.category != null ? p.category : 'none'));
const enforceDiversity = distinctCats.size >= 3;
const perCatCap = Math.ceil(TARGET_COUNT / 2);
const perCat = new Map();
const selected = [];

for (const p of ranked) {
  const cat = p.category != null ? p.category : 'none';
  const used = perCat.get(cat) || 0;
  if (enforceDiversity && used >= perCatCap) continue;
  selected.push(p);
  perCat.set(cat, used + 1);
  if (selected.length >= TARGET_COUNT) break;
}

// QA gate: throw if minimum not met (Error Trigger workflow catches this)
if (selected.length < MIN_COUNT) {
  throw new Error(`QA gate failed: only ${selected.length} valid deals after selection, minimum ${MIN_COUNT}`);
}

return selected.map(p => ({ json: p }));
